package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.VariableDeclarationExpr;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.CatchClause;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.stmt.TryStmt;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-file-or-directory>");
            System.exit(1);
        }

        Path sourcePath = Paths.get(args[0]);

        if (Files.isDirectory(sourcePath)) {
            Files.walk(sourcePath)
                .filter(p -> p.toString().endsWith(".java"))
                .forEach(Main::processFile);
        } else {
            processFile(sourcePath);
        }

        System.out.println("Transformation complete.");
    }

    private static void processFile(Path javaFile) {
        try {
            System.out.println("Processing: " + javaFile);

            CompilationUnit cu = StaticJavaParser.parse(javaFile);

            new FopFactoryFixVisitor().visit(cu, null);

            try (java.io.FileWriter writer = new java.io.FileWriter(javaFile.toFile())) {
                writer.write(cu.toString());
            }

        } catch (IOException e) {
            System.err.println("Error processing " + javaFile + ": " + e.getMessage());
        }
    }

    private static class FopFactoryFixVisitor extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(MethodDeclaration method, Void arg) {
            super.visit(method, arg);

            BlockStmt body = method.getBody().orElse(null);
            if (body == null) return;

            List<Statement> statements = body.getStatements();
            for (int i = 0; i < statements.size(); i++) {
                Statement stmt = statements.get(i);

                if (stmt instanceof com.github.javaparser.ast.stmt.ExpressionStmt) {
                    com.github.javaparser.ast.stmt.ExpressionStmt exprStmt = 
                        (com.github.javaparser.ast.stmt.ExpressionStmt) stmt;
                    Expression expr = exprStmt.getExpression();

                    if (expr instanceof VariableDeclarationExpr) {
                        VariableDeclarationExpr varDecl = (VariableDeclarationExpr) expr;
                        if (varDecl.getVariables().size() == 1) {
                            var varVar = varDecl.getVariable(0);
                            if (varVar.getInitializer().isPresent() && 
                                varVar.getInitializer().get() instanceof MethodCallExpr) {

                                MethodCallExpr methodCall = 
                                    (MethodCallExpr) varVar.getInitializer().get();

                                if ("FopFactory".equals(methodCall.getScope()
                                        .map(e -> e.toString())
                                        .orElse("")) && 
                                    "newInstance".equals(methodCall.getNameAsString()) &&
                                    methodCall.getArguments().isEmpty()) {

                                    ObjectCreationExpr fileCreation = new ObjectCreationExpr();
                                    fileCreation.setType("File");
                                    fileCreation.addArgument("\".\"");
                                    methodCall.addArgument(fileCreation);

                                    TryStmt tryStmt = new TryStmt();
                                    BlockStmt tryBlock = new BlockStmt();

                                    NodeList<Statement> remainingStmts = new NodeList<>();
                                    for (int j = i + 1; j < statements.size(); j++) {
                                        remainingStmts.add(statements.get(j));
                                    }
                                    tryBlock.addStatement(stmt);
                                    tryBlock.getStatements().addAll(remainingStmts);

                                    tryStmt.setTryBlock(tryBlock);

                                    CatchClause catchClause = new CatchClause();
                                    catchClause.setParameter(
                                        new com.github.javaparser.ast.Parameter(
                                            new ClassOrInterfaceType(null, "SAXException"),
                                            "e"
                                        )
                                    );
                                    BlockStmt catchBlock = new BlockStmt();
                                    catchBlock.addStatement(
                                        new com.github.javaparser.ast.stmt.ThrowStmt(
                                            new ObjectCreationExpr()
                                                .setType("ExportServiceException")
                                                .addArgument("\"Error creating FopFactory\"")
                                                .addArgument(new com.github.javaparser.ast.expr.NameExpr("e"))
                                        )
                                    );
                                    catchClause.setBody(catchBlock);
                                    tryStmt.getCatchClauses().add(catchClause);

                                    statements.subList(i, statements.size()).clear();
                                    statements.add(tryStmt);

                                    method.addThrownException(
                                        new ClassOrInterfaceType(null, "org.xml.sax.SAXException")
                                    );

                                    System.out.println("  Fixed: Wrapped FopFactory.newInstance() with SAXException handling");
                                    return;
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

