                                    BlockStmt tryBlock = new BlockStmt();

                                    NodeList<Statement> remainingStmts = new NodeList<>();
                                    for (int j = i + 1; j < statements.size(); j++) {
                                        remainingStmts.add(statements.get(j));
                                    }
